import { useState, useEffect, useCallback, useMemo, type ChangeEvent } from 'react'
import Button from '@mui/material/Button'
import { torrentUploadHost } from 'utils/Hosts'
import axios from 'axios'
import { useTranslation } from 'react-i18next'
import {
  useMediaQuery,
  TextField,
  FormControl,
  FormHelperText,
  Select,
  MenuItem,
  IconButton,
  type SelectChangeEvent,
} from '@mui/material'
import CircularProgress from '@mui/material/CircularProgress'
import { Delete as DeleteIcon } from '@mui/icons-material'
import { ButtonWrapper } from 'style/DialogStyles'
import { StyledDialog, StyledHeader } from 'style/CustomMaterialUiStyles'
import useOnStandaloneAppOutsideClick from 'utils/useOnStandaloneAppOutsideClick'
import { TORRENT_CATEGORIES } from 'components/categories'
import { NoImageIcon } from 'icons'
import { useQuery } from '@tanstack/react-query'
import { getTorrents } from 'utils/Utils'
import useChangeLanguage from 'utils/useChangeLanguage'
import parseTorrent from 'parse-torrent'
import type { MultiAddFileState, TorrentStat } from 'types/api'

import { parseTorrentTitle, checkImageURL, getMoviePosters } from './helpers'
import { MultiFileRow, MultiFilePoster, MultiFileInfo, MultiFileList } from './style'

interface FileRowProps {
  file: File
  fileState: MultiAddFileState
  index: number
  onUpdate: (updates: Partial<MultiAddFileState>) => void
  onRemove: () => void
  existingTorrents: TorrentStat[]
}

function FileRow({ file, fileState, index, onUpdate, onRemove, existingTorrents }: FileRowProps) {
  const { t } = useTranslation()
  const [currentLang] = useChangeLanguage()
  const handleTitleChange = ({ target: { value } }: ChangeEvent<HTMLInputElement>) => onUpdate({ title: value })
  const handleCategoryChange = ({ target: { value } }: SelectChangeEvent<string>) => onUpdate({ category: value })
  const handlePosterChange = ({ target: { value } }: ChangeEvent<HTMLInputElement>) => {
    onUpdate({ poster: value })
    checkImageURL(value).then(ok => onUpdate({ isPosterOk: ok }))
  }

  useEffect(() => {
    parseTorrent.remote(file, (err, parsed) => {
      if (!err && parsed?.infoHash) {
        const existing = existingTorrents.find(tor => tor.hash === parsed.infoHash)
        if (existing) {
          const updates: Partial<MultiAddFileState> = { infoHash: parsed.infoHash, alreadyExists: true }
          if (existing.title) updates.title = existing.title
          if (existing.category) updates.category = String(existing.category)
          if (existing.poster) {
            updates.poster = existing.poster
            updates.isPosterOk = true
          }
          onUpdate(updates)
          return
        }
        onUpdate({ infoHash: parsed.infoHash })
      }
    })

    const posterLang = currentLang === 'ru' ? 'ru' : 'en'
    parseTorrentTitle(file, ({ parsedTitle, originalName }) => {
      if (!originalName) return
      onUpdate({ originalName, parsedTitle: parsedTitle || '' })

      const searchTitle = parsedTitle || originalName
      if (searchTitle) {
        getMoviePosters(searchTitle, posterLang).then(urls => {
          if (urls && urls.length > 0) {
            checkImageURL(urls[0]).then(ok => {
              if (ok) onUpdate({ poster: urls[0], isPosterOk: true })
            })
          }
        })
      }
    })
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [file])

  return (
    <MultiFileRow>
      <MultiFilePoster>
        <span className='file-index'>{index + 1}</span>
        {fileState.isPosterOk ? (
          <img src={fileState.poster} alt='poster' />
        ) : (
          <div style={{ opacity: 0.3, width: 40, height: 40 }}>
            <NoImageIcon />
          </div>
        )}
      </MultiFilePoster>

      <MultiFileInfo>
        <TextField
          onChange={handleTitleChange}
          value={fileState.title}
          margin='dense'
          label={t('AddDialog.TitleBlank')}
          type='text'
          variant='outlined'
          fullWidth
          size='small'
        />

        <TextField
          onChange={handlePosterChange}
          value={fileState.poster}
          margin='dense'
          label={t('AddDialog.AddPosterLinkInput')}
          type='url'
          variant='outlined'
          fullWidth
          size='small'
        />

        <FormControl fullWidth size='small' style={{ marginTop: 4 }}>
          <FormHelperText style={{ padding: '0 0.5em' }}>{t('AddDialog.CategoryHelperText')}</FormHelperText>
          <Select
            value={fileState.category}
            margin='dense'
            onChange={handleCategoryChange}
            variant='outlined'
            fullWidth
            defaultValue=''
          >
            <MenuItem value=''>
              <em>—</em>
            </MenuItem>
            {TORRENT_CATEGORIES.map(cat => (
              <MenuItem key={cat.key} value={cat.key}>
                {t(cat.name)}
              </MenuItem>
            ))}
          </Select>
        </FormControl>
      </MultiFileInfo>

      <IconButton onClick={onRemove} size='medium'>
        <DeleteIcon />
      </IconButton>
    </MultiFileRow>
  )
}

export interface MultiAddDialogProps {
  files: File[]
  handleClose: () => void
}

export default function MultiAddDialog({ files, handleClose }: MultiAddDialogProps) {
  const { t } = useTranslation()
  const fullScreen = useMediaQuery('(max-width:930px)')
  const ref = useOnStandaloneAppOutsideClick(handleClose)
  const [isSaving, setIsSaving] = useState(false)

  const { data: torrents } = useQuery({
    queryKey: ['torrents'],
    queryFn: getTorrents,
    retry: 1,
  })
  const existingTorrents = torrents || []

  const [fileList, setFileList] = useState<MultiAddFileState[]>(() =>
    files.map(f => ({
      file: f,
      title: f.name.replace(/\.torrent$/i, ''),
      category: '',
      poster: '',
      isPosterOk: false,
      originalName: '',
      parsedTitle: '',
      infoHash: '',
      alreadyExists: false,
    })),
  )

  const newFiles = useMemo(() => fileList.filter(item => !item.alreadyExists), [fileList])
  const newCount = newFiles.length

  const handleUpdate = useCallback((index: number, updates: Partial<MultiAddFileState>) => {
    setFileList(prev => prev.map((item, i) => (i === index ? { ...item, ...updates } : item)))
  }, [])

  const handleRemove = useCallback(
    (index: number) => {
      setFileList(prev => {
        const next = prev.filter((_, i) => i !== index)
        if (next.length === 0) handleClose()
        return next
      })
    },
    [handleClose],
  )

  const handleSaveAll = () => {
    setIsSaving(true)
    const uploads = newFiles.map(item => {
      const data = new FormData()
      data.append('save', 'true')
      data.append('file', item.file)
      item.title && data.append('title', item.title)
      item.poster && data.append('poster', item.poster)
      item.category && data.append('category', item.category)
      return axios.post(torrentUploadHost(), data).catch(() => {})
    })
    Promise.all(uploads).finally(handleClose)
  }

  return (
    <StyledDialog open onClose={handleClose} fullScreen={fullScreen} fullWidth maxWidth='md' ref={ref}>
      <StyledHeader>
        {t('AddNewTorrent')} ({newCount})
      </StyledHeader>

      <MultiFileList>
        {(() => {
          let visibleIndex = 0
          return fileList.map((item, index) => {
            if (item.alreadyExists) return null
            const currentIndex = visibleIndex++
            return (
              <FileRow
                key={item.file.name + index}
                file={item.file}
                fileState={item}
                index={currentIndex}
                onUpdate={updates => handleUpdate(index, updates)}
                onRemove={() => handleRemove(index)}
                existingTorrents={existingTorrents}
              />
            )
          })
        })()}
      </MultiFileList>

      <ButtonWrapper>
        <Button onClick={handleClose} color='secondary' variant='outlined'>
          {t('Cancel')}
        </Button>

        <Button
          variant='contained'
          style={{ minWidth: '110px' }}
          disabled={newCount === 0}
          onClick={handleSaveAll}
          color='secondary'
        >
          {isSaving ? <CircularProgress style={{ color: 'white' }} size={20} /> : `${t('Add')} (${newCount})`}
        </Button>
      </ButtonWrapper>
    </StyledDialog>
  )
}
